   130→// If the cache service is implemented, we capture the request duration as a metric. The service is expected to write any response headers.
   131→func (m *CachingMiddleware) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
   132→	if req == nil {
   133→		return m.BaseHandler.CallResource(ctx, req, sender)
   134→	}
   135→
   136→	reqCtx := contexthandler.FromContext(ctx)
   137→	if reqCtx == nil {
   138→		return m.BaseHandler.CallResource(ctx, req, sender)
   139→	}
   140→
   141→	// time how long this request takes
   142→	start := time.Now()
